"use strict";(self.webpackChunkbcsd_blog=self.webpackChunkbcsd_blog||[]).push([[7538],{3749:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/what-is-bcsd","metadata":{"permalink":"/introduce/what-is-bcsd","source":"@site/@introduce/what-is-bcsd.mdx","title":"BCSD \uac00\uc774\ub4dc 1\ud3b8: BCSD\ub780?","description":"BCSD\ub780?","date":"2025-05-05T00:00:00.000Z","tags":[],"readingTime":4.415,"hasTruncateMarker":true,"authors":[{"name":"Haesung Jung","url":"https://github.com/junghaesung79","email":"gotjd0230@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/96577250?v=4","key":"junghaesung79"}],"frontMatter":{"date":"2025-05-05T00:00:00.000Z","authors":"junghaesung79","title":"BCSD \uac00\uc774\ub4dc 1\ud3b8: BCSD\ub780?","description":"BCSD\ub780?","keywords":["BCSD"]},"unlisted":false,"nextItem":{"title":"BCSD \uac00\uc774\ub4dc 2\ud3b8: BCSD\uc5d0\uc11c\uc758 \ud65c\ub3d9","permalink":"/introduce/bcsd-activity"}},"content":"{/* truncate */}\\n\\n---\\n\\n### BCSD\ub294 \u201c\uc990\uac81\uac8c \uc77c\ud558\uace0 \uc5f4\uc2ec\ud788 \ub178\ub294 IT \ud2b9\uc131\ud654 \ub3d9\uc544\ub9ac\u201d\ub97c \uc9c0\ud5a5\ud569\ub2c8\ub2e4!\\n\\n\uc0ac\uc2e4 \uc774 \uc2ac\ub85c\uac74\uc740 \uc81c\uac00 \uba4b\ub300\ub85c \ubd99\uc778 \uac83\uc774\uad6c\uc694, \uc774\uc804 \uc120\ubc30\ub4e4\uc740 \uc880 \ub354 \uc5c4\uaca9\ud588\ub2e4\uace0 \ud569\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \ucd5c\uadfc 1~2\ub144 \uc0ac\uc774\uc5d0 \ubd84\uc704\uae30\uac00 \ub9ce\uc774 \ub2ec\ub77c\uc84c\uace0, \uc800\ub3c4 \ub3d9\uc544\ub9ac\uc5d0\uc11c \uc7ac\ubc0c\ub294 \ucd94\uc5b5\uc744 \ub9ce\uc774 \ub9cc\ub4e4\uc5c8\uae30 \ub54c\ubb38\uc774 \uc774\ub807\uac8c \uc9c0\uc5c8\uc2b5\ub2c8\ub2e4!\\n\\n---\\n\\n## BCSD \uc774\ub984\uc758 \ub73b\\n\\n**Build Communities, Share Dreams**\\n\\n\uc774\uac83\ub3c4 \uc62c\ud574(2025\ub144) \ubc14\ub00c\uc5c8\uc2b5\ub2c8\ub2e4. \uc6d0\ub798\ub294 BCSD Lab, Beyond the Computer Software Developer Laboratory \uc600\ub294\ub370, \uac1c\ubc1c \uc9c1\uad70\uc774 \uc544\ub2cc \ud2b8\ub799\ub4e4\uc774 \uc810\uc810 \ub298\uc5b4\ub098\uba74\uc11c \uc870\uae08 \uc5b4\uc0c9\ud55c \ub73b\uc774 \ub418\uc5c8\uc2b5\ub2c8\ub2e4. \uadf8\ub9ac\uace0 BCSD\ub97c \ucef4\uacf5 \ub3d9\uc544\ub9ac\ub77c\uace0 \uc624\ud574\ud558\ub294 \ubd84\ub4e4\ub3c4 \ub9ce\uc558\uc8e0. \uadf8\ub807\uac8c \uc5ec\ub7ec \ub17c\uc758 \ub05d\uc5d0 \ube0c\ub79c\ub529\uc744 \ub2e4\uc2dc\ud558\uac8c \ub418\uc5c8\uace0, \uc704\uc5d0 \ub098\uc628 BCSD\uac00 \ub410\uc2b5\ub2c8\ub2e4.\\n\\n\uac01\uae30 \ub2e4\ub978 \uafc8\uc744 \uac00\uc9c4 \ud559\uc0dd\ub4e4\uc774 \ubaa8\uc5ec \uacf5\ub3d9\uccb4\ub97c \ub9cc\ub4e4\uace0, \uadf8 \uc548\uc5d0\uc11c \uc11c\ub85c\uc758 \uafc8\uc744 \ub098\ub204\uba70 \uc131\uc7a5\ud558\ub294 \uacf5\uac04\uc774\ub77c\ub294 \uc758\ubbf8\ub97c \ub2f4\uace0 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n<div style={{ display: \\"flex\\", flexDirection: \\"column\\", width: \\"100%\\" }}>\\n    <img src=\\"/img/@introduce/bcsd-mean.png\\" alt=\\"\uc774\ubbf8\uc9c0\\" style={{ display: \\"flex\\", justifyContent: \\"center\\" }} />\\n</div>\\n\\n---\\n\\n## \uc8fc\uc694 \ud589\uc0ac/\ud65c\ub3d9\\n\\n- **\ube44\ucf58(BCSD Conference) & \uc6cc\ud06c\uc0f5**\\n\\n    \ube44\ucf58\uc740 \ub3d9\uc544\ub9ac\uc6d0 \uc804\uccb4\uac00 \ubaa8\uc5ec \ub124\ud2b8\uc6cc\ud0b9\ud558\uace0, \uc2e4\ubb34 \uc9c0\uc2dd\uacfc \uacbd\ud5d8\uc744 \ub098\ub204\ub294 \ub300\ud615 \ud589\uc0ac\uc785\ub2c8\ub2e4. \uc9c1\ud6c4\uc5d0 1\ubc15 2\uc77c\ub85c \ub808\ud06c\ub808\uc774\uc158\uacfc \ubc14\ubca0\ud050\ub97c \uc990\uae30\ub294 \uc6cc\ud06c\uc0f5\uc774 \uc9c4\ud589\ub429\ub2c8\ub2e4.\\n\\n    BCSD\uac00 \uc6cc\ub099 \ud504\ub85c\uc81d\ud2b8\uc640 \uad50\uc721 \uc911\uc2ec\uc758 \ub3d9\uc544\ub9ac\ub77c\uc11c \ub300\ud45c\ub418\ub294 \ud589\uc0ac\uac00 \ubcc4\ub85c \uc5c6\uc2b5\ub2c8\ub2e4. \ud558\uc9c0\ub9cc \uac00\ub054 \uc11c\uc6b8\uc18c\uc7ac \uae30\uc5c5 \uc138\ubbf8\ub098\uc2e4\uc744 \ube4c\ub824\uc11c \uc11c\ub85c \uacf5\ubd80\ud55c \ub0b4\uc6a9\uc744 \ubc1c\ud45c\ud574\ubcf4\uac70\ub098, \uc11c\uc6b8\uc5d0\uc11c \uc9c4\ud589\ud558\ub294 IT \uad00\ub828 \ud589\uc0ac\uc5d0 \ub2e4\uac19\uc774 \ucc38\uc5ec\ud558\uae30\ub3c4 \ud569\ub2c8\ub2e4. \uac8c\uc784 \ud2b8\ub799\uc758 \uacbd\uc6b0 \ubc24\uc744 \uc0c8\uba74\uc11c \uac01\uc790 \uac8c\uc784 \ud558\ub098\ub97c \ub9cc\ub4dc\ub294 \uac8c\uc784\uc7bc\uc744 \uc9c4\ud589\ud558\uae30\ub3c4 \ud569\ub2c8\ub2e4.\\n\\n- **\ud504\ub85c\uc81d\ud2b8 \uac1c\ubc1c**\\n\\n    \uad50\ub0b4 \uc11c\ube44\uc2a4 \u2018\ucf54\uc778\u2019\ucc98\ub7fc \uc2e4\uc81c \uc0ac\uc6a9\uc790\uac00 \uc788\ub294 \uc11c\ube44\uc2a4\uc758 \uc2e0\uaddc \uae30\ub2a5/\uac1c\uc120 \uacfc\uc81c\ub97c \uc218\ud589\ud569\ub2c8\ub2e4.\\n\\n    \ub610\ub294 \ud2b8\ub799 \ub0b4\uc5d0\uc11c \uc790\uccb4 \ud504\ub85c\uc81d\ud2b8\ub97c \uae30\ud68d\ud558\uc5ec \uac1c\ubc1c\ud569\ub2c8\ub2e4.\\n\\n- **\ud2b8\ub799\ubcc4 \uc2a4\ud130\ub514**\\n\\n    \uac01 \ud2b8\ub799 \ubcc4\ub85c \ucd5c\uc2e0 \uae30\uc220 \ud2b8\ub80c\ub4dc, \uc2e4\ubb34 \uc9c0\uc2dd\uc758 \uc2b5\ub4dd \ubc0f \uc801\uc6a9\uc744 \uc704\ud55c \uc2a4\ud130\ub514\ub97c \uc9c4\ud589\ud569\ub2c8\ub2e4.\\n\\n- **\ube44\uae30\ub108 \uad50\uc721**\\n\\n    \uc2e0\uc785 \ud68c\uc6d0\ub4e4\uc744 \ub300\uc0c1\uc73c\ub85c \ud2b8\ub799\ubcc4 \uae30\ucd08 \uc9c0\uc2dd \uc2b5\ub4dd\uc744 \uc704\ud55c \uad50\uc721\uc744 \uc9c4\ud589\ud569\ub2c8\ub2e4.\\n\\n---\\n\\n## BCSD\uac00 \ud574\uacb0\ud558\uace0\uc790 \ud558\ub294 \ubb38\uc81c\\n\\n- **\uc9c0\ub9ac\uc801 \ud55c\uacc4**\\n    \\n    \ubcd1\ucc9c\uc774\ub77c\ub294 \uc9c0\ub9ac\uc801 \ud55c\uacc4\ub85c \uc778\ud574 \ud604\uc5c5 \ub124\ud2b8\uc6cc\ud0b9, \ucd5c\uc2e0 \uae30\uc220 \ud2b8\ub80c\ub4dc \uc811\uadfc\uc774 \uc5b4\ub824\uc6b4 \ubb38\uc81c\ub97c\\n    \\n    \uba58\ud1a0\ubd84\ub4e4\uacfc \uc7ac\ud559\uc0dd\uc744 \uac04\uc811\uc801\uc73c\ub85c \uc5f0\uacb0\uc2dc\ud0a4\ub294 \uac83\uc73c\ub85c \uacf5\uac04\uc744 \ud655\uc7a5\uc2dc\ud0a4\ub294 \uac83\uc73c\ub85c \ud574\uacb0\ud558\uace0\uc790 \ud569\ub2c8\ub2e4.\\n    \\n- **\uc2e4\ubb34 \uad50\uc721 \uc778\ud504\ub77c \ubd80\uc871**\\n    \\n    \uc774\ub860 \uc911\uc2ec \ub300\ud559 \ucee4\ub9ac\ud058\ub7fc\uc758 \ud55c\uacc4\ub97c \ubcf4\uc644\ud558\uae30 \uc704\ud574,\\n    \\n    \ud2b8\ub799\ubcc4 \uc2e4\ubb34 \uad50\uc721, \uc2e4\uc81c \ud504\ub85c\uc81d\ud2b8 \uacbd\ud5d8, \ud3ec\ud2b8\ud3f4\ub9ac\uc624 \uad6c\ucd95 \ud658\uacbd\uc744 \uc81c\uacf5\ud569\ub2c8\ub2e4.\\n    \\n- **\uc9c0\uc2dd \uc804\ub2ec\uc758 \ub2e8\uc808**\\n    \\n    \uc878\uc5c5\uc0dd-\uc7ac\ud559\uc0dd-\uba58\ud1a0\uac00 \ud568\uaed8\ud558\ub294 \uc120\uc21c\ud658 \uad6c\uc870\ub97c \ud1b5\ud574\\n    \\n    \uc9c0\uc2dd\uacfc \uacbd\ud5d8, \ucde8\uc5c5 \ub178\ud558\uc6b0\ub4e4\uc744 \uc720\uae30\uc801\uc73c\ub85c \uc804\uc218\ud569\ub2c8\ub2e4.\\n    \\n\\n---\\n\\n\ub2e4\uc74c \ud3b8\uc5d0\uc11c\ub294 BCSD\uc5d0\uc11c\uc758 \ud65c\ub3d9\uacfc \uc9c1\uae09\ubcc4 \uc5ed\ud560\uc5d0 \ub300\ud574 \uc548\ub0b4\ud569\ub2c8\ub2e4!"},{"id":"/bcsd-activity","metadata":{"permalink":"/introduce/bcsd-activity","source":"@site/@introduce/bcsd-activity.mdx","title":"BCSD \uac00\uc774\ub4dc 2\ud3b8: BCSD\uc5d0\uc11c\uc758 \ud65c\ub3d9","description":"BCSD\uc5d0\uc11c\uc758 \ud65c\ub3d9","date":"2025-05-04T00:00:00.000Z","tags":[],"readingTime":4.34,"hasTruncateMarker":true,"authors":[{"name":"Haesung Jung","url":"https://github.com/junghaesung79","email":"gotjd0230@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/96577250?v=4","key":"junghaesung79"}],"frontMatter":{"date":"2025-05-04T00:00:00.000Z","authors":"junghaesung79","title":"BCSD \uac00\uc774\ub4dc 2\ud3b8: BCSD\uc5d0\uc11c\uc758 \ud65c\ub3d9","description":"BCSD\uc5d0\uc11c\uc758 \ud65c\ub3d9","keywords":["BCSD"]},"unlisted":false,"prevItem":{"title":"BCSD \uac00\uc774\ub4dc 1\ud3b8: BCSD\ub780?","permalink":"/introduce/what-is-bcsd"},"nextItem":{"title":"BCSD \uac00\uc774\ub4dc 3\ud3b8: \ud2b8\ub799 \uc18c\uac1c","permalink":"/introduce/introduce-tracks"}},"content":"{/* truncate */}\\n\\n---\\n\\n## \ube44\uae30\ub108, \ub808\uade4\ub7ec, \uba58\ud1a0 \ud65c\ub3d9 \ud55c\ub208\uc5d0 \ubcf4\uae30\\n\\n### \ube44\uae30\ub108\\n\\n- **\uc8fc\uc694 \ud65c\ub3d9**\\n    - \ud2b8\ub799\ubcc4 \uae30\ucd08 \uae30\uc220 \uc2a4\ud0dd \uad50\uc721 \ud504\ub85c\uadf8\ub7a8 \ucc38\uc5ec\\n    - \uae30\ucd08 \uc9c0\uc2dd\uc744 \ud65c\uc6a9\ud55c \uc18c\uaddc\ubaa8 \ud68c\uace0 \ud504\ub85c\uc81d\ud2b8 \uc9c4\ud589\\n- **\uae30\uac04**\\n    - \uc77c\ubc18\uc801\uc73c\ub85c \ud55c \ud559\uae30(5~6\uac1c\uc6d4)\\n\\n\ube44\uae30\ub108\ub294 BCSD\ub97c \ucc98\uc74c \uc811\ud558\uace0 \uc785\ubb38\ud558\ub294 \ub2e8\uacc4\ub85c, \uc57d 6\uac1c\uc6d4 \ub3d9\uc548 \uac01\uc790 \uc120\ud0dd\ud55c \ud2b8\ub799\uc758 \ucee4\ub9ac\ud058\ub7fc\uc5d0 \ub530\ub77c \uccb4\uacc4\uc801\uc73c\ub85c \uad50\uc721\uc744 \ubc1b\uc73c\uba70 \uc131\uc7a5\ud558\ub294 \uc2dc\uac04\uc744 \uac16\uc2b5\ub2c8\ub2e4.\\n\\n\uc774 \uacfc\uc815\uc5d0\uc11c\ub294 \uc0dd\uac01\ubcf4\ub2e4 \ub9ce\uc740 \uc2dc\uac04\uacfc \ub178\ub825\uc774 \ud544\uc694\ud558\uc9c0\ub9cc, \uc9c8\ubb38\uc744 \ub9ce\uc774 \ud558\uace0 \uc801\uadf9\uc801\uc73c\ub85c \ucc38\uc5ec\ud560\uc218\ub85d \ub354 \ub9ce\uc740 \uac83\uc744 \uc5bb\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ube44\uae30\ub108 \ub54c\uc758 \ud301\uc744 \ud558\ub098 \ub9d0\uc500\ub4dc\ub9ac\uc790\uba74, \ub808\uade4\ub7ec \ud55c \uba85\uacfc \uce5c\ud574\uc838\uc11c \uad81\uae08\ud55c \uc810\uc744 \uc790\uc8fc \uc9c8\ubb38\ud574\ubcf4\uac70\ub098, \uac19\uc740 \ud2b8\ub799\uc5d0 \uc788\ub294 \uce5c\uad6c\ub97c \ub77c\uc774\ubc8c \uc0bc\uc544 \uc11c\ub85c \uc790\uadf9\uc744 \uc8fc\uba70 \ud568\uaed8 \uc131\uc7a5\ud574\ubcf4\ub294 \uac83\ub3c4 \uc88b\uc740 \ubc29\ubc95\uc785\ub2c8\ub2e4.\\n\\n---\\n\\n### \ub808\uade4\ub7ec\\n\\n- **\uc8fc\uc694 \ud65c\ub3d9**\\n    - \uc2e4\uc81c \uc11c\ube44\uc2a4 \uac1c\ubc1c \ub4f1 \uc2e4\uc804 \ud504\ub85c\uc81d\ud2b8 \ucc38\uc5ec\\n    - \ub2e4\ub978 \ud2b8\ub799\uacfc\uc758 \ud611\uc5c5 \ud504\ub85c\uc81d\ud2b8 \ubc0f \ub124\ud2b8\uc6cc\ud0b9 \ud65c\ub3d9\\n    - \ube44\uae30\ub108\ub97c \uc704\ud55c \uad50\uc721 \uc138\uc158 \uc8fc\ub3c4 \ubc0f \ubcf4\uc870\\n    - \ucd5c\uc2e0 \uae30\uc220 \ud2b8\ub80c\ub4dc \uc5f0\uad6c, \uc2ec\ud654 \uc2a4\ud130\ub514 \uadf8\ub8f9 \uc6b4\uc601\\n    - \ucde8\uc5c5 \uc900\ube44(\ud604\uc5c5 \uba58\ud1a0 \uc5f0\uacc4 \ub4f1)\\n\\n\uc2e4\uc81c \uc11c\ube44\uc2a4 \uac1c\ubc1c \ud504\ub85c\uc81d\ud2b8\uc5d0 \ucc38\uc5ec\ud558\uac70\ub098, \ube44\uae30\ub108\ub97c \uc704\ud55c \uad50\uc721 \uc138\uc158\uc744 \uc8fc\ub3c4\ud558\uace0 \uc6b4\uc601\ud558\ub294 \ub4f1 BCSD\uc758 \uc8fc\ucd95\uc774 \ub418\uc5b4 \ub3d9\uc544\ub9ac\uc758 \ub2e4\uc591\ud55c \ud504\ub85c\uadf8\ub7a8\uc744 \uc774\ub04c\uc5b4\uac11\ub2c8\ub2e4.\\n\\n\uc774 \uacfc\uc815\uc744 \ud1b5\ud574 \uc2e4\ubb34 \ub2a5\ub825\uacfc \ub354\ubd88\uc5b4 \ub9ac\ub354\uc2ed \ub610\ud55c \ud0a4\uc6b8 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ubcf8\uc778 \ud2b8\ub799 \ubfd0\ub9cc \uc544\ub2c8\ub77c \ub2e4\ub978 \ud2b8\ub799\uacfc\ub3c4 \uc811\uc810\uc774 \ub9ce\uc774 \uc0dd\uae30\ub294\ub370, \uc0c8\ub85c\uc6b4 \uc778\uac04\uad00\uacc4\ub97c \ud615\uc131\ud558\uae30 \uc88b\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n### \uba58\ud1a0\\n\\n- **\uc8fc\uc694 \ud65c\ub3d9**\\n    - \ub808\uade4\ub7ec, \ube44\uae30\ub108 \uba64\ubc84\ub4e4\uc758 \uae30\uc220\uc801 \uc131\uc7a5 \uc9c0\uc6d0\\n    - \uc790\uc18c\uc11c \ucca8\uc0ad, \ucde8\uc5c5 \uba58\ud1a0\ub9c1 \ub4f1 \uc2e4\uc9c8\uc801 \uc9c4\ub85c \uc9c0\uc6d0\\n\\n\uba58\ud1a0\ubd84\ub4e4\uc740 \uac01\uc790 \ubcf8\uc778\uc758 \uc9c1\uc7a5\uc5d0 \ub2e4\ub2c8\uba74\uc11c \uac04\uc811\uc801\uc73c\ub85c \ub808\uade4\ub7ec\ub4e4\uc744 \uc9c0\uc6d0\ud569\ub2c8\ub2e4.\\n\\n\uc815\ub9d0 \ub300\ub2e8\ud55c \ubd84\ub4e4\uc774 \ub9ce\uc544\uc11c, \uac00\ub054 \ud559\uad50\uc5d0 \uc624\uac70\ub098 \ube44\ucf58 \uc6cc\ud06c\uc0f5\uc5d0\uc11c \ub9cc\ub098 \uc774\uc57c\uae30\ub97c \ub098\ub204\ub294 \uac83\ub9cc\uc73c\ub85c\ub3c4 \uc778\uc0ac\uc774\ud2b8\ub97c \uc5bb\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n---\\n\\n## \ub2e8\uacc4\ubcc4 \uc131\uc7a5 \uacfc\uc815\\n\\n1. **\uc785\ubb38(\ube44\uae30\ub108)**\\n    - \ub3d9\uc544\ub9ac \ud65c\ub3d9\uc5d0 \ucc98\uc74c \ucc38\uc5ec\\n    - \ud2b8\ub799\ubcc4 \uae30\ucd08 \uad50\uc721 \ubc0f \uc18c\uaddc\ubaa8 \ud504\ub85c\uc81d\ud2b8\ub97c \ud1b5\ud574 \uae30\ubcf8\uae30 \ub2e4\uc9c0\uae30\\n2. **\uc2e4\uc804(\ub808\uade4\ub7ec)**\\n    - \uc2e4\uc804 \ud504\ub85c\uc81d\ud2b8 \ucc38\uc5ec\uc640 \uad50\uc721 \uc8fc\ub3c4, \ud611\uc5c5 \uacbd\ud5d8\uc744 \ud1b5\ud574 \uc2e4\ubb34 \uc5ed\ub7c9 \uac15\ud654\\n    - \uc678\ubd80 \ud589\uc0ac, \ub124\ud2b8\uc6cc\ud0b9, \uc2a4\ud130\ub514 \ub4f1 \ub2e4\uc591\ud55c \ud65c\ub3d9\uc744 \ud1b5\ud574 \uc131\uc7a5\\n3. **\uba58\ud1a0**\\n    - \ucde8\uc5c5 \ub4f1 \uc77c\uc815 \uae30\uc900 \ucda9\uc871 \uc2dc \uba58\ud1a0\ub85c \uc2b9\uaca9\\n    - \ud6c4\ubc30 \uad50\uc721, \uc9c4\ub85c \uba58\ud1a0\ub9c1 \ub4f1 \uc120\uc21c\ud658 \uad6c\uc870\uc758 \ud575\uc2ec \uc5ed\ud560 \uc218\ud589\\n\\n---\\n\\n## \ub808\uade4\ub7ec \uc804\ud658 \uae30\uc900\\n\\n### \ube44\uae30\ub108 \u2192 \ub808\uade4\ub7ec\\n\\n- \ud2b8\ub799\ubcc4 \uad50\uc721 \uc774\uc218 \uc644\ub8cc\\n- \ud68c\uace0 \ud504\ub85c\uc81d\ud2b8 \uc644\ub8cc\\n- \ubcf8\uc778\uc758 \uc804\ud658 \ud76c\ub9dd\\n- \ud68c\uace0 \uba74\uc811 \ud1b5\uacfc\\n\\n### *\uc989\uc2dc \uc804\ud658*\\n\\n- \ube44\uae30\ub108 \uad50\uc721 \ub0b4\uc6a9\uc744 \uc774\ubbf8 \ucda9\ubd84\ud788 \uc54c\uace0 \uc788\uc5b4 \ucd94\uac00 \uad50\uc721\uc774 \ud544\uc694\ud558\uc9c0 \uc54a\ub2e4\uace0 \ud310\ub2e8\ud558\ub294 \uacbd\uc6b0\\n- \ud2b8\ub799\uc7a5 \ubc0f \uc784\uc6d0\uc9c4\uacfc \ud68c\uace0 \uba74\uc811 \uc9c4\ud589\\n\\n---\\n\\n\ub2e4\uc74c \ud3b8\uc5d0\uc11c\ub294 BCSD\uc5d0 \uc874\uc7ac\ud558\ub294 \ud2b8\ub799\ub4e4\uc5d0 \ub300\ud574 \uc548\ub0b4\ud569\ub2c8\ub2e4!"},{"id":"/introduce-tracks","metadata":{"permalink":"/introduce/introduce-tracks","source":"@site/@introduce/introduce-tracks.mdx","title":"BCSD \uac00\uc774\ub4dc 3\ud3b8: \ud2b8\ub799 \uc18c\uac1c","description":"\ud2b8\ub799 \uc18c\uac1c","date":"2025-05-03T00:00:00.000Z","tags":[],"readingTime":3.655,"hasTruncateMarker":true,"authors":[{"name":"Haesung Jung","url":"https://github.com/junghaesung79","email":"gotjd0230@gmail.com","imageURL":"https://avatars.githubusercontent.com/u/96577250?v=4","key":"junghaesung79"}],"frontMatter":{"date":"2025-05-03T00:00:00.000Z","authors":"junghaesung79","title":"BCSD \uac00\uc774\ub4dc 3\ud3b8: \ud2b8\ub799 \uc18c\uac1c","description":"\ud2b8\ub799 \uc18c\uac1c","keywords":["BCSD"]},"unlisted":false,"prevItem":{"title":"BCSD \uac00\uc774\ub4dc 2\ud3b8: BCSD\uc5d0\uc11c\uc758 \ud65c\ub3d9","permalink":"/introduce/bcsd-activity"}},"content":"{/* truncate */}\\n\\n---\\n\\nBCSD\uc5d0\ub294 2025\ub144 \uae30\uc900 \ucd1d 9\uac1c\uc758 \ud2b8\ub799\uc774 \uc788\uc2b5\ub2c8\ub2e4.\\n\\n\ucd08\ucc3d\uae30\uc5d0\ub294 \uc548\ub4dc\ub85c\uc774\ub4dc, \ubc31\uc5d4\ub4dc, \uac8c\uc784\\n\\n\uadf8 \ub2e4\uc74c\uc73c\ub85c \ud504\ub860\ud2b8\uc5d4\ub4dc, UI/UX \uadf8\ub9ac\uace0 iOS\\n\\n24\ub144\ub3c4\uc5d0 PM, DA \ud2b8\ub799\uc774 \ucd94\uac00\ub418\uba74\uc11c \ube44\uc2b7\ud55c \uc2dc\uae30\uc5d0 UI/UX \ud2b8\ub799\uc758 \uc774\ub984\uc774 Design\uc73c\ub85c \ubc14\ub00c\uc5c8\uace0\\n\\n25\ub144\ub3c4\uc5d0 \ubcf4\uc548 \ud2b8\ub799\uc774 \uc2dc\ud5d8 \uc6b4\uc601\ub418\uba74\uc11c \uc9c0\uae08\uc758 \ud615\ud0dc\uac00 \ub418\uc5c8\uc2b5\ub2c8\ub2e4. (\ud2c0\ub9b0 \ub0b4\uc6a9\uc774 \uc788\uc73c\uba74 \ub9d0\uc500\ud574\uc8fc\uc138\uc694!)\\n\\n---\\n\\n### \ud504\ub860\ud2b8\uc5d4\ub4dc(FrontEnd, FE)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - \uc6f9\uc0ac\uc774\ud2b8\uc640 \uc571\uc758 \uc0ac\uc6a9\uc790 \ud654\uba74\uc744 \uad6c\ud604\ud558\ub294 \ubd84\uc57c\ub85c, \ucd5c\uc2e0 \ud504\ub860\ud2b8\uc5d4\ub4dc \uae30\uc220\uc744 \uc775\ud788\uace0 \uc2e4\ubb34\ud615 \uc6f9 \uac1c\ubc1c \uacbd\ud5d8\uc744 \uc313\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220**\\n    - React, TypeScript, TanStack Query\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/front-end/react/introduce-FE-2025)\\n\\n---\\n\\n### \ubc31\uc5d4\ub4dc(BackEnd, BE)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - \ub370\uc774\ud130 \ucc98\ub9ac, \uc800\uc7a5, \uad00\ub9ac\uc640 API \uc124\uacc4 \ubc0f \uad6c\ud604\uc744 \ub2f4\ub2f9\ud558\uba70, \uc2e4\ubb34\uc5d0\uc11c \ub110\ub9ac \uc4f0\uc774\ub294 \uc11c\ubc84 \ubc0f \ub370\uc774\ud130\ubca0\uc774\uc2a4 \uae30\uc220\uc744 \ubc30\uc6c1\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220**\\n    - Java, Spring Boot, MySQL, Docker\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/back-end/react/introduce-BE-2025)\\n\\n---\\n\\n### \uc548\ub4dc\ub85c\uc774\ub4dc(Android)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - Kotlin \uae30\ubc18\uc73c\ub85c \uc548\ub4dc\ub85c\uc774\ub4dc \uc571\uc744 \uac1c\ubc1c\ud558\uace0, \uc2e4\uc81c \ubc30\ud3ec\uae4c\uc9c0 \uacbd\ud5d8\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220**\\n    - Kotlin, Android Jetpack\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/android/react/introduce-Android-2025)\\n\\n---\\n\\n### iOS\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - Swift\ub97c \ud65c\uc6a9\ud574 Apple \uc0dd\ud0dc\uacc4\uc758 \ub124\uc774\ud2f0\ube0c \uc571\uc744 \uac1c\ubc1c\ud558\uba70, \uc2e4\uc0ac\uc6a9\uc790\uc5d0\uac8c \uc81c\uacf5\ud558\ub294 \uc571 \uc81c\uc791 \uacbd\ud5d8\uc744 \uc313\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220**\\n    - Swift, UIKit\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/ios/react/introduce-iOS-2025)\\n\\n---\\n\\n### \ub514\uc790\uc778(Design)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - UI/UX \ub514\uc790\uc778 \uae30\ucd08\ubd80\ud130 \uc2e4\ubb34 \ud504\ub85c\uc81d\ud2b8\uae4c\uc9c0, \uc0ac\uc6a9\uc790 \uc911\uc2ec\uc758 \uc11c\ube44\uc2a4 \uc124\uacc4\uc640 \ub514\uc790\uc778 \ud234 \ud65c\uc6a9 \uc5ed\ub7c9\uc744 \ud0a4\uc6b8 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220/\ub3c4\uad6c**\\n    - Figma, Photoshop, Illustrator\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/design/react/introduce-Design-2025)\\n\\n---\\n\\n### PM(ProductManager)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - \uc11c\ube44\uc2a4 \uae30\ud68d, \uc77c\uc815 \uad00\ub9ac, \ud300\uc6d0 \uc870\uc728 \ub4f1 IT \ud504\ub85c\uc81d\ud2b8\uc758 \uc804\ubc18\uc801\uc778 \uc6b4\uc601\uacfc \uc2e4\ubb34 \uacbd\ud5d8\uc744 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \ub3c4\uad6c**\\n    - Notion, Figma\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/product-manager/react/introduce-PM-2025)\\n\\n---\\n\\n### DA(DataAnalyst)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - \ub370\uc774\ud130 \uc218\uc9d1, \ubd84\uc11d, \uc2dc\uac01\ud654 \ub4f1 \uc2e4\uc804 \ub370\uc774\ud130 \ubd84\uc11d\uac00\uc758 \uc5c5\ubb34\ub97c \ub2e8\uacc4\ubcc4\ub85c \uacbd\ud5d8\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220/\ub3c4\uad6c**\\n    - Python, SQL, Tableau, Looker Studio\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/data-analyst/react/introduce-DA-2025)\\n\\n---\\n\\n### \uac8c\uc784(Game)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - Unity, Unreal Engine\uc744 \ud65c\uc6a9\ud55c 2D/3D \uac8c\uc784 \uac1c\ubc1c\uacfc \ud300 \ud504\ub85c\uc81d\ud2b8 \uacbd\ud5d8\uc744 \ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220/\ub3c4\uad6c**\\n    - Unity, C#\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/game/react/introduce-Game-2025)\\n\\n---\\n\\n### \ubcf4\uc548(Security)\\n\\n- **\ud2b8\ub799 \ud2b9\uc9d5**\\n    - \uc6f9 \ud574\ud0b9, \uc2dc\uc2a4\ud15c \ud574\ud0b9 \ub4f1 \ub2e4\uc591\ud55c \ubcf4\uc548 \ubd84\uc57c\uc758 \uae30\ucd08\ubd80\ud130 \uc2e4\uc804 \ud504\ub85c\uc81d\ud2b8\uae4c\uc9c0 \uacbd\ud5d8\ud560 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\\n- **\uc8fc\uc694 \uae30\uc220/\ub3c4\uad6c**\\n    - Python, \ucde8\uc57d\uc810 \ubd84\uc11d \ud234, \ub124\ud2b8\uc6cc\ud06c \ubd84\uc11d \ud234\\n- [\uc790\uc138\ud788 \ubcf4\uae30](https://blog.bcsdlab.com/security/react/introduce-Security-2025)"}]}')}}]);